var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말 이대로 돌아가실 생각이십니까, 주인님?","JPN":"本当にこのままお戻りになるのですか、ご主人様？","ENG":"Are you really going to leave like this, Mistress?","TWN":"主人，您確定要就這樣打道回府嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"어린 늑대와 만난다고 해서 꽤 기대를 하신 것 같은데요.","JPN":"幼い狼に会えるとずいぶん楽しみにされておられたと思いますが。","ENG":"I thought you were looking forward to meeting the young Wolf.","TWN":"您不是很期待可以和幼狼見面嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 흥미가 없어졌다고 하면 거짓말이지.","JPN":"まあ、興味がなくなったと言ったら嘘になる。","ENG":"Well, I’m still interested in her.","TWN":"嗯，如果說沒興趣是在騙人的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 딱 이 정도가 좋아.","JPN":"じゃが、これくらいがちょうど良いのじゃ。","ENG":"But this is good enough for me.","TWN":"不過點到就好。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"궁금하다고 자꾸 냄비 뚜껑을 열어 보면 결국 요리를 망치는 법이지.","JPN":"気になるからと何度も鍋の蓋を開けてしまうと、\\nせっかくの料理が台無しになる。","ENG":"You just go with the flow, otherwise you’ll ruin it.","TWN":"畢竟俗話說得好，小不忍則亂大謀的嘛～"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 주인님의 인내력은 감탄스럽습니다.","JPN":"やはり、ご主人様の忍耐力は感心するばかりでございます。","ENG":"Your patience is truly impressive, Mistress.","TWN":"我對主人的耐心真是嘆為觀止！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그보다 가짜 구세주 일당들도 제법이지 않느냐?","JPN":"それより、偽りの救世主一味もなかなかやるではないか。","ENG":"I’m also impressed with the False Savior’s lot.","TWN":"不過假的救世主那群人有兩下子嘛！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"고작해야 등대 같은 하찮은 물건으로 <color=#ffd34c>패배자</color>들을 불러들일 생각을 하다니, 아주 창의적이야.","JPN":"たかが灯台ごときで<color=#ffd34c>敗北者</color>らを呼び寄せようとするとは、\\n実に斬新な発想じゃな。","ENG":"Baiting the <color=#ffd34c>losers</color> with something trivial like the Lighthouse, it’s very creative.","TWN":"竟然可以想到用那個什麼破爛燈塔，把那群<color=#ffd34c>失敗者</color>引出來，非常有創意的想法！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"약해빠진 녀석들이라 그런지 머리가 참 잘 돌아간다니까.","JPN":"軟弱が故に、頭が切れる連中じゃ。","ENG":"They are weak, but clever.","TWN":"是因為他們肉體虛弱，所以腦袋特別靈活嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"옳은 말씀이십니다.","JPN":"そのとおりでございます。","ENG":"I agree, Mistress.","TWN":"主人說的是。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론 위대하신 저의 주인님께선 강함과 현명함을 모두 겸비하고 계시지만요.","JPN":"もちろん、偉大なる我がご主人様はそれを上回る強さと賢明さを\\nすべて兼ね備えておられますが。","ENG":"But you have both strength and intelligence, which makes you the most impressive.","TWN":"不過我們偉大的主人當然是能力與智慧兼具囉！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 주인님! 갑자기 얼굴이 붉어지셨군요!","JPN":"おや、どうされましたかご主人様？　急に顔が赤くなられて。","ENG":"Mistress, your face is red!","TWN":"主人！您的臉突然變得好紅喔！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"혹시 무언가 심기를 거스르는 일이 떠오르셨습니까. 그렇다면 이 시종에게 말씀만 하시지요.","JPN":"何か気に障るようなことが思い浮かばれましたか。\\nでしたら、この僕に何なりとお申し付けください。","ENG":"Did something offend you? Please tell me, and I will get chase it away!","TWN":"請問是想到什麼煩心的事嗎？有的話請不要客氣，儘管跟我說！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"크흠, 너무 노골적인 칭찬만 이어지니 아무리 나라도 조금 부끄럽달까…….","JPN":"コホン、あまりにも露骨な褒め言葉ばかりじゃから、\\nいくら妾とはいえ少しは恥じらうこともあるのじゃ……","ENG":"Ahem, the constant showering of compliments is a bit embarrassing, even for me...","TWN":"咳咳，收到這麼直白的稱讚，我也是會害羞的好嗎……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그럴 수가! 주인님께서는 어찌 이리 겸손하기도 하신지……!","JPN":"なんということでしょう！　ご主人様はどうしてこんなにも謙虚なのか……！","ENG":"That’s just impossible! My mistress also has the virtue of modesty!","TWN":"我的天啊！主人為何這麼謙卑……！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 도마, 그 옛날 저희 일족을 구하기 위해 주인님께 영원한 충성을 맹세한 것을 단 한 순간도 후회해 본 적 없습니다.","JPN":"このドマ、その昔我が一族を救うために\\nご主人様に永遠の忠誠を誓ったことを、一瞬たりとも後悔したことはありません。","ENG":"I, Doma, never regretted the day I swore the oath to serve you to save my tribe.","TWN":"多馬我，自從主人拯救我們全家族後，就發誓要為主人上刀山下油鍋，而我也從未後悔過。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"……그래. 그러고 보니 그런 일도 있었지.","JPN":"……ああ。そういえばそんなこともあったのう。","ENG":"... Oh, yes. I think I remember the event.","TWN":"……嗯嗯，是有這麼一回事沒錯。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그러면 가자꾸나, 시종.","JPN":"では行くとしよう、僕よ。","ENG":"Let’s go, my servant.","TWN":"那我們走吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"다시 한 번 게임이 시작될 테니까.","JPN":"再びゲームが始まるぞ。","ENG":"The game will soon start again.","TWN":"遊戲又預備要開始囉～"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};